void ParsePana(string l) { Print($"松下: {l.Split(',')[1]}°C"); }
void ParseOmron(string l) { var t = l.Split(';')[0].Split('=')[1]; Print($"欧姆龙: {t}°C"); }
Serial.Open();
string? line;
while ((line=Serial.ReadLine())!=null)
